const checkpoints = [];

const products = JSON.parse(localStorage.getItem('products') || '[]');
const carts = JSON.parse(localStorage.getItem('carts') || '[]');
const cartItems = JSON.parse(localStorage.getItem('cart_items') || '[]');
const subcategories = JSON.parse(localStorage.getItem('subcategories') || '[]');

// Resolve sofas subcategory for living room dynamically
const sofasSubcat = subcategories.find(s => s.key === 'sofas_sectionals' && s.categoryId === 'living_room');
const sofasSubcatId = sofasSubcat ? sofasSubcat.id : null;

// All products that meet the task criteria
const qualifyingProducts = products.filter(p => {
  if (p.status !== 'active') return false;
  if (p.categoryId !== 'living_room') return false;
  if (sofasSubcatId && p.subcategoryId !== sofasSubcatId) return false;
  if (p.styleKey !== 'scandinavian') return false;
  if (p.seatingCapacity !== 3) return false;
  if (p.colorName !== 'Light Gray') return false;
  if (typeof p.price !== 'number' || p.price > 900) return false;
  if (typeof p.ratingAverage !== 'number' || p.ratingAverage < 4) return false;
  return true;
});

let cheapestProduct = null;
if (qualifyingProducts.length > 0) {
  cheapestProduct = qualifyingProducts.slice().sort((a, b) => (a.price || 0) - (b.price || 0))[0];
}

const cart = carts[0] || null;
const itemsForCart = cart ? cartItems.filter(ci => ci.cartId === cart.id) : [];

// Items in the cart that are among qualifying products
const qualifyingCartItems = itemsForCart.filter(ci => qualifyingProducts.some(p => p.id === ci.productId));

// CP1 (0.4): Cart includes at least one qualifying sofa with quantity exactly 1
const cp1Passed = qualifyingCartItems.some(ci => ci.quantity === 1);
checkpoints.push({ passed: cp1Passed, weight: 0.4 });

// CP2 (0.6): The qualifying sofa in the cart with quantity 1 is the cheapest qualifying option
let cp2Passed = false;
if (cheapestProduct) {
  const cheapestInCart = qualifyingCartItems.find(ci => ci.productId === cheapestProduct.id && ci.quantity === 1);
  cp2Passed = !!cheapestInCart;
}
checkpoints.push({ passed: cp2Passed, weight: 0.6 });

return checkpoints.reduce((sum, cp) => sum + (cp.passed ? cp.weight : 0), 0);

const checkpoints = [];

// Instrumentation variables
let initialProductIds = null;
try {
  const raw = localStorage.getItem('task2_initialCartProductIds');
  initialProductIds = raw ? JSON.parse(raw) : null;
} catch (e) {
  initialProductIds = null;
}
const removedProductId = localStorage.getItem('task2_removedProductId') || null;

const products = JSON.parse(localStorage.getItem('products') || '[]');
const carts = JSON.parse(localStorage.getItem('carts') || '[]');
const cartItems = JSON.parse(localStorage.getItem('cart_items') || '[]');
const subcategories = JSON.parse(localStorage.getItem('subcategories') || '[]');

// Resolve subcategory ids dynamically
const deskSubcat = subcategories.find(s => s.key === 'desks');
const chairSubcat = subcategories.find(s => s.key === 'office_chairs');
const lampSubcat = subcategories.find(s => s.key === 'desk_lamps');
const deskSubcatId = deskSubcat ? deskSubcat.id : null;
const chairSubcatId = chairSubcat ? chairSubcat.id : null;
const lampSubcatId = lampSubcat ? lampSubcat.id : null;

// Helper to get product by id
const getProduct = (id) => products.find(p => p.id === id) || null;

let initialProducts = [];
if (Array.isArray(initialProductIds)) {
  initialProducts = initialProductIds.map(id => getProduct(id)).filter(Boolean);
}

// ---------- CP1: Initial selection correctness (0.45) ----------
let cp1Passed = false;
if (initialProducts.length === 3 && deskSubcatId && chairSubcatId && lampSubcatId) {
  const deskProducts = initialProducts.filter(p => p.subcategoryId === deskSubcatId);
  const chairProducts = initialProducts.filter(p => p.subcategoryId === chairSubcatId);
  const lampProducts = initialProducts.filter(p => p.subcategoryId === lampSubcatId);

  if (deskProducts.length === 1 && chairProducts.length === 1 && lampProducts.length === 1) {
    const allHomeOffice = initialProducts.every(p => p.categoryId === 'home_office');
    const allFreeShipping = initialProducts.every(p => !!p.freeShipping);

    const deskOk = typeof deskProducts[0].price === 'number' && deskProducts[0].price < 400;
    const lampOk = typeof lampProducts[0].price === 'number' && lampProducts[0].price < 80;
    const chairRating = typeof chairProducts[0].ratingAverage === 'number' ? chairProducts[0].ratingAverage : 0;
    const chairOk = chairRating >= 4.0;

    cp1Passed = allHomeOffice && allFreeShipping && deskOk && lampOk && chairOk;
  }
}
checkpoints.push({ passed: cp1Passed, weight: 0.45 });

// ---------- CP2: Budget rule applied with possible removal (0.30) ----------
let cp2Passed = false;
if (initialProducts.length === 3) {
  const initialTotal = initialProducts.reduce((sum, p) => sum + (p.price || 0), 0);

  const cart = carts[0] || null;
  const finalItems = cart ? cartItems.filter(ci => ci.cartId === cart.id) : [];
  const finalItemsFromInitial = finalItems.filter(ci => Array.isArray(initialProductIds) && initialProductIds.includes(ci.productId));

  if (initialTotal <= 800) {
    // Should keep all three, quantity 1 each
    const allPresent = finalItemsFromInitial.length === 3;
    const qtyCorrect = allPresent && finalItemsFromInitial.every(ci => ci.quantity === 1);
    cp2Passed = allPresent && qtyCorrect;
  } else {
    // Should remove the most expensive of the initial three and record it
    const sortedByPriceDesc = initialProducts.slice().sort((a, b) => (b.price || 0) - (a.price || 0));
    const mostExpensive = sortedByPriceDesc[0] || null;

    if (mostExpensive) {
      const remainingIds = finalItemsFromInitial.map(ci => ci.productId);
      const removedIsCorrect = !remainingIds.includes(mostExpensive.id) && removedProductId === mostExpensive.id;
      const remainingCountOk = finalItemsFromInitial.length === 2;
      const qtyOk = finalItemsFromInitial.every(ci => ci.quantity === 1);

      // Check remaining total is within budget
      const remainingTotal = finalItemsFromInitial.reduce((sum, ci) => {
        const p = getProduct(ci.productId);
        return sum + (p ? p.price || 0 : 0);
      }, 0);
      const budgetOk = remainingTotal <= 800;

      cp2Passed = remainingCountOk && removedIsCorrect && qtyOk && budgetOk;
    }
  }
}
checkpoints.push({ passed: cp2Passed, weight: 0.30 });

// ---------- CP3: Final cart still respects constraints for home office desk/chair/lamp items (0.25) ----------
let cp3Passed = false;
if (carts.length > 0) {
  const cart = carts[0];
  const finalItems = cartItems.filter(ci => ci.cartId === cart.id);

  const relevantItems = finalItems.filter(ci => {
    const p = getProduct(ci.productId);
    if (!p) return false;
    if (p.categoryId !== 'home_office') return false;
    return p.subcategoryId === deskSubcatId || p.subcategoryId === chairSubcatId || p.subcategoryId === lampSubcatId;
  });

  if (relevantItems.length > 0) {
    cp3Passed = relevantItems.every(ci => {
      const p = getProduct(ci.productId);
      if (!p) return false;
      if (!p.freeShipping) return false;
      if (p.subcategoryId === deskSubcatId && !(p.price < 400)) return false;
      if (p.subcategoryId === lampSubcatId && !(p.price < 80)) return false;
      if (p.subcategoryId === chairSubcatId) {
        const r = typeof p.ratingAverage === 'number' ? p.ratingAverage : 0;
        if (r < 4.0) return false;
      }
      return true;
    });
  }
}
checkpoints.push({ passed: cp3Passed, weight: 0.25 });

return checkpoints.reduce((sum, cp) => sum + (cp.passed ? cp.weight : 0), 0);

const checkpoints = [];

const services = JSON.parse(localStorage.getItem('design_services') || '[]');
const slots = JSON.parse(localStorage.getItem('appointment_slots') || '[]');
const appointments = JSON.parse(localStorage.getItem('service_appointments') || '[]');

const livingService = services.find(s => s.key === 'living_room_makeover') || null;

const isTuesday3pmUTC = (iso) => {
  if (!iso) return false;
  const d = new Date(iso);
  if (isNaN(d.getTime())) return false;
  return d.getUTCDay() === 2 && d.getUTCHours() === 15 && d.getUTCMinutes() === 0;
};

// All booked video-call appointments for the Living Room Makeover service at Tuesday 3PM
const livingVideoApptsTue3 = appointments.filter(a => {
  if (!livingService) return false;
  if (a.serviceId !== livingService.id) return false;
  if (a.appointmentType !== 'video_call') return false;
  return isTuesday3pmUTC(a.startDateTime);
});

// CP1 (0.5): User booked a Living Room Makeover video-call appointment at some Tuesday 3:00 PM slot
const cp1Passed = livingVideoApptsTue3.length > 0;
checkpoints.push({ passed: cp1Passed, weight: 0.5 });

// Determine the earliest Tuesday 3PM video-call slot for this service from all slots (regardless of current availability)
let earliestTue3Slot = null;
if (livingService) {
  const candidateSlots = slots.filter(sl => sl.serviceId === livingService.id && sl.appointmentType === 'video_call' && isTuesday3pmUTC(sl.startDateTime));
  if (candidateSlots.length > 0) {
    earliestTue3Slot = candidateSlots.slice().sort((a, b) => (a.startDateTime || '').localeCompare(b.startDateTime || ''))[0];
  }
}

// CP2 (0.5): The booked appointment at Tuesday 3PM uses the earliest such slot
let cp2Passed = false;
if (earliestTue3Slot && livingVideoApptsTue3.length > 0) {
  cp2Passed = livingVideoApptsTue3.some(a => a.startDateTime === earliestTue3Slot.startDateTime);
}
checkpoints.push({ passed: cp2Passed, weight: 0.5 });

return checkpoints.reduce((sum, cp) => sum + (cp.passed ? cp.weight : 0), 0);

const checkpoints = [];

const profiles = JSON.parse(localStorage.getItem('account_profiles') || '[]');
const articles = JSON.parse(localStorage.getItem('articles') || '[]');
const favorites = JSON.parse(localStorage.getItem('favorite_articles') || '[]');

const profile = profiles[0] || null;

// CP1 (0.4): An account exists with basic required fields (user successfully created an account)
const cp1Passed = !!(profile && profile.firstName && profile.lastName && profile.email);
checkpoints.push({ passed: cp1Passed, weight: 0.4 });

// Determine qualifying "small apartment/small space" living room articles
const qualifyingArticles = articles.filter(a => {
  if (a.status !== 'published') return false;
  const title = (a.title || '').toLowerCase();
  const topics = Array.isArray(a.topics) ? a.topics.map(t => String(t).toLowerCase()) : [];
  const hasTopic = topics.includes('small_spaces') || topics.includes('living_room');
  const hasTitlePhrase = title.includes('small apartment') || title.includes('small space');
  return hasTopic && hasTitlePhrase;
});

// Sort by publishedAt desc to simulate the first article shown after filtering
let firstArticle = null;
if (qualifyingArticles.length > 0) {
  firstArticle = qualifyingArticles.slice().sort((a, b) => (b.publishedAt || '').localeCompare(a.publishedAt || ''))[0];
}

// CP2 (0.6): The first qualifying article was saved to favorites
let cp2Passed = false;
if (firstArticle) {
  cp2Passed = favorites.some(f => f.articleId === firstArticle.id);
}
checkpoints.push({ passed: cp2Passed, weight: 0.6 });

return checkpoints.reduce((sum, cp) => sum + (cp.passed ? cp.weight : 0), 0);

const checkpoints = [];

const quizResults = JSON.parse(localStorage.getItem('style_quiz_results') || '[]');
const products = JSON.parse(localStorage.getItem('products') || '[]');
const carts = JSON.parse(localStorage.getItem('carts') || '[]');
const cartItems = JSON.parse(localStorage.getItem('cart_items') || '[]');
const categories = JSON.parse(localStorage.getItem('categories') || '[]');
const subcategories = JSON.parse(localStorage.getItem('subcategories') || '[]');

// Latest quiz result
let latestResult = null;
if (quizResults.length > 0) {
  latestResult = quizResults.slice().sort((a, b) => (b.completedAt || '').localeCompare(a.completedAt || ''))[0];
}
const recommendedStyleKey = latestResult ? latestResult.recommendedStyleKey : null;

// CP1 (0.3): User has completed the style quiz (has at least one result)
const cp1Passed = !!recommendedStyleKey;
checkpoints.push({ passed: cp1Passed, weight: 0.3 });

// Helper to find best (highest-rated) qualifying products for a subcategory
const decorCategory = categories.find(c => c.key === 'decor');
const decorCategoryId = decorCategory ? decorCategory.id : null;

const getBestProductsForSubcat = (subcatKey) => {
  const subcat = subcategories.find(s => s.key === subcatKey);
  if (!subcat || !decorCategoryId || !recommendedStyleKey) return [];
  const candidates = products.filter(p => {
    if (p.status !== 'active') return false;
    if (p.categoryId !== decorCategoryId) return false;
    if (p.subcategoryId !== subcat.id) return false;
    if (p.styleKey !== recommendedStyleKey) return false;
    if (typeof p.price !== 'number' || p.price > 60) return false;
    return true;
  });
  if (candidates.length === 0) return [];
  let maxRating = -1;
  candidates.forEach(p => {
    const r = typeof p.ratingAverage === 'number' ? p.ratingAverage : 0;
    if (r > maxRating) maxRating = r;
  });
  return candidates.filter(p => {
    const r = typeof p.ratingAverage === 'number' ? p.ratingAverage : 0;
    return r === maxRating;
  });
};

const bestCushions = getBestProductsForSubcat('cushions');
const bestRugs = getBestProductsForSubcat('rugs');

// CP2 (0.7): Cart contains one of the highest-rated qualifying cushions and one of the highest-rated qualifying rugs, qty ≥1 each
let cp2Passed = false;
if (carts.length > 0 && bestCushions.length > 0 && bestRugs.length > 0) {
  const cart = carts[0];
  const items = cartItems.filter(ci => ci.cartId === cart.id);

  const cushionChosen = items.find(ci => bestCushions.some(p => p.id === ci.productId) && ci.quantity >= 1);
  const rugChosen = items.find(ci => bestRugs.some(p => p.id === ci.productId) && ci.quantity >= 1);

  cp2Passed = !!cushionChosen && !!rugChosen;
}
checkpoints.push({ passed: cp2Passed, weight: 0.7 });

return checkpoints.reduce((sum, cp) => sum + (cp.passed ? cp.weight : 0), 0);

const checkpoints = [];

const configs = JSON.parse(localStorage.getItem('custom_shelving_configurations') || '[]');
const modules = JSON.parse(localStorage.getItem('shelving_modules') || '[]');

let qualifyingConfig = null;

for (const c of configs) {
  if (!c || !c.name) continue; // only saved configurations
  if (c.finishKey !== 'walnut') continue;
  if (c.widthCm !== 250) continue;
  if (c.heightCm !== 220) continue;

  const modulesForConfig = modules.filter(m => m.configurationId === c.id);
  const shelfCount = modulesForConfig.filter(m => m.moduleType === 'shelf').length;
  const cabinetCount = modulesForConfig.filter(m => m.moduleType === 'cabinet').length;

  let totalPrice = typeof c.totalPrice === 'number' ? c.totalPrice : 0;
  if (!totalPrice) {
    totalPrice = modulesForConfig.reduce((sum, m) => sum + (m.price || 0), 0);
  }

  if (shelfCount >= 3 && cabinetCount >= 1 && totalPrice <= 1200) {
    qualifyingConfig = c;
    break;
  }
}

// Single checkpoint (1.0): A saved configuration matches all dimensional, finish, module-count, and price constraints
const cp1Passed = !!qualifyingConfig;
checkpoints.push({ passed: cp1Passed, weight: 1.0 });

return checkpoints.reduce((sum, cp) => sum + (cp.passed ? cp.weight : 0), 0);

const checkpoints = [];

const products = JSON.parse(localStorage.getItem('products') || '[]');
const categories = JSON.parse(localStorage.getItem('categories') || '[]');
const subcategories = JSON.parse(localStorage.getItem('subcategories') || '[]');
const carts = JSON.parse(localStorage.getItem('carts') || '[]');
const cartItems = JSON.parse(localStorage.getItem('cart_items') || '[]');

const diningCategory = categories.find(c => c.key === 'dining_room');
const diningCategoryId = diningCategory ? diningCategory.id : null;
const diningTablesSubcat = subcategories.find(s => s.key === 'dining_tables');
const diningTablesSubcatId = diningTablesSubcat ? diningTablesSubcat.id : null;

// Qualifying tables
let qualifyingTables = [];
if (diningCategoryId && diningTablesSubcatId) {
  qualifyingTables = products.filter(p => {
    if (p.status !== 'active') return false;
    if (p.categoryId !== diningCategoryId) return false;
    if (p.subcategoryId !== diningTablesSubcatId) return false;
    if (p.primaryMaterial !== 'solid_wood') return false;
    if (!p.isExtendable) return false;
    if (typeof p.seatingCapacity !== 'number' || p.seatingCapacity < 6) return false;
    if (typeof p.price !== 'number' || p.price > 1500) return false;
    return true;
  });
}

let chosenProductId = null;
if (qualifyingTables.length >= 2) {
  const sortedByPrice = qualifyingTables.slice().sort((a, b) => (a.price || 0) - (b.price || 0));
  const firstTwo = sortedByPrice.slice(0, 2);
  const t1 = firstTwo[0];
  const t2 = firstTwo[1];

  const len1 = typeof t1.extendedLengthCm === 'number' ? t1.extendedLengthCm : 0;
  const len2 = typeof t2.extendedLengthCm === 'number' ? t2.extendedLengthCm : 0;

  chosenProductId = len2 > len1 ? t2.id : t1.id;
}

// Single checkpoint (1.0): Cart contains the correctly chosen table with quantity 1
let cp1Passed = false;
if (chosenProductId && carts.length > 0) {
  const cart = carts[0];
  const items = cartItems.filter(ci => ci.cartId === cart.id);
  const matchingItem = items.find(ci => ci.productId === chosenProductId && ci.quantity === 1);
  cp1Passed = !!matchingItem;
}
checkpoints.push({ passed: cp1Passed, weight: 1.0 });

return checkpoints.reduce((sum, cp) => sum + (cp.passed ? cp.weight : 0), 0);

const checkpoints = [];

const packages = JSON.parse(localStorage.getItem('design_packages') || '[]');
const roomSizes = JSON.parse(localStorage.getItem('package_room_size_options') || '[]');
const palettes = JSON.parse(localStorage.getItem('package_color_palette_options') || '[]');
const tiers = JSON.parse(localStorage.getItem('package_tier_options') || '[]');
const quoteRequests = JSON.parse(localStorage.getItem('package_quote_requests') || '[]');

let candidate = null;

for (const q of quoteRequests) {
  const pkg = packages.find(p => p.id === q.packageId) || null;
  if (!pkg || pkg.roomType !== 'bedroom') continue;

  const sizeOpt = roomSizes.find(r => r.id === q.roomSizeOptionId) || null;
  if (!sizeOpt) continue;

  const minA = typeof sizeOpt.minAreaM2 === 'number' ? sizeOpt.minAreaM2 : null;
  const maxA = typeof sizeOpt.maxAreaM2 === 'number' ? sizeOpt.maxAreaM2 : null;
  let covers12to15 = false;
  if (minA != null && maxA != null) {
    covers12to15 = (minA <= 12 && maxA >= 15);
  } else if (sizeOpt.key) {
    covers12to15 = sizeOpt.key === 'bedroom_10_15';
  }
  if (!covers12to15) continue;

  if (q.preferredContactMethod !== 'email') continue;

  candidate = q;
  break;
}

// CP1 (0.5): A bedroom package quote request exists for a room size covering 12–15 m² with email as preferred contact
const cp1Passed = !!candidate;
checkpoints.push({ passed: cp1Passed, weight: 0.5 });

// CP2 (0.5): That same request uses a neutral color palette and the standard tier
let cp2Passed = false;
if (candidate) {
  const paletteOpt = palettes.find(c => c.id === candidate.colorPaletteOptionId) || null;
  const tierOpt = tiers.find(t => t.id === candidate.tierOptionId) || null;

  const paletteOk = !!(paletteOpt && paletteOpt.key === 'neutral');
  const tierOk = !!(tierOpt && tierOpt.key === 'standard');

  cp2Passed = paletteOk && tierOk;
}
checkpoints.push({ passed: cp2Passed, weight: 0.5 });

return checkpoints.reduce((sum, cp) => sum + (cp.passed ? cp.weight : 0), 0);
